function normProv(s: string): string {
  if (!s) return '';
  return s
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\([^)]*\)/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

export function regionKey(countryCode: string, province: string): string {
  return `${(countryCode || '').trim().toUpperCase()}|${normProv(province)}`;
}

// Lazy indexes: region key -> its index, and species -> Set<regionIndex>.
let _regionIdx: Map<string, number> | null = null;
let _expected: Map<string, Set<number>> | null = null;
function regionIndex(countryCode: string, province: string): number {
  if (!_regionIdx) {
    _regionIdx = new Map();
    RANGE_REGIONS.forEach((r, i) => _regionIdx!.set(r, i));
  }
  const i = _regionIdx.get(regionKey(countryCode, province));
  return i === undefined ? -1 : i;
}
function expectedIndex(): Map<string, Set<number>> {
  if (!_expected) {
    _expected = new Map();
    for (const [name, ids] of Object.entries(RANGE_EXPECTED)) {
      _expected.set(name, new Set(ids));
    }
  }
  return _expected;
}

// True if we have any range data for this admin-1 region. When false the
// caller can't trust admin-1 tiering here (unknown/unmatched province) and
// should fall back to realm ranking for the whole list.
export function hasRegion(countryCode: string, province: string): boolean {
  return regionIndex(countryCode, province) >= 0;
}

export type RangeStatus = 'expected' | 'country' | 'elsewhere' | 'unknown';

// Where does `name` sit relative to the user's admin-1 region?
//   expected  - normally occurs in the user's state/province
//   country   - not the user's province, but expected elsewhere in-country
//   elsewhere - has range data, but none in the user's country (rare/out of range)
//   unknown   - no GBIF range data for this species (fall back to realm ranking)
export function rangeStatusFor(
  name: string,
  countryCode: string,
  province: string
): RangeStatus {
  const ids = expectedIndex().get(name);
  if (!ids || ids.size === 0) return 'unknown';
  const here = regionIndex(countryCode, province);
  if (here >= 0 && ids.has(here)) return 'expected';
  const cc = (countryCode || '').trim().toUpperCase() + '|';
  for (const i of ids) {
    if (RANGE_REGIONS[i].startsWith(cc)) return 'country';
  }
  return 'elsewhere';
}
